import{c as n,Q as a,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned","description":"","frontmatter":{"title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned","authors":"Nghi D. Q. Bui","published":"2026-03-05T00:00:00.000Z","source":"https://arxiv.org/html/2603.05344v1"},"headers":[],"relativePath":"research/papers/2026-03-05-opendev-terminal-agents-scaffolding.md","filePath":"research/papers/2026-03-05-opendev-terminal-agents-scaffolding.md","lastUpdated":1779894392000}'),t={name:"research/papers/2026-03-05-opendev-terminal-agents-scaffolding.md"};function o(l,e,r,p,c,d){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering-and-lessons-learned" tabindex="-1">Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned <a class="header-anchor" href="#building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering-and-lessons-learned" aria-label="Permalink to &quot;Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned&quot;">​</a></h1><p><strong>Authors</strong>: Nghi D. Q. Bui (OpenDev)<br><strong>Published</strong>: March 5, 2026<br><strong>arXiv ID</strong>: 2603.05344v1<br><strong>Source</strong>: <a href="https://arxiv.org/html/2603.05344v1" target="_blank" rel="noreferrer">https://arxiv.org/html/2603.05344v1</a><br><strong>License</strong>: CC BY 4.0</p><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>OpenDev is an open-source command-line agent designed for autonomous software engineering tasks. The system addresses three core challenges in long-running terminal agents: managing finite context windows during extended sessions, preventing destructive operations despite arbitrary shell access, and extending functionality without overwhelming the model&#39;s prompt budget.</p><p>The architecture implements a compound AI system with workload-specialized model routing, dual-agent separation between planning and execution, lazy tool discovery, and adaptive context compaction. The system accumulates project-specific knowledge across sessions through automated memory mechanisms and counteracts instruction degradation via event-driven system reminders.</p><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><h3 id="_1-1-problem-statement-terminal-agent-challenges" tabindex="-1">1.1 Problem Statement: Terminal Agent Challenges <a class="header-anchor" href="#_1-1-problem-statement-terminal-agent-challenges" aria-label="Permalink to &quot;1.1 Problem Statement: Terminal Agent Challenges&quot;">​</a></h3><p>Building reliable autonomous agents for terminal-based software engineering requires solving three interconnected challenges:</p><p><strong>Challenge 1: Context Window Management</strong></p><ul><li>Extended sessions can span dozens or hundreds of operations</li><li>Terminal output can be verbose, consuming tokens rapidly</li><li>Naive approaches exhaust context windows mid-task</li><li>Need: Intelligent compaction and selective history management</li></ul><p><strong>Challenge 2: Safety and Destructive Operations</strong></p><ul><li>Terminal agents have arbitrary shell access (read AND write)</li><li>Risk of unintended file deletion, data corruption, system misconfiguration</li><li>Need: Defense-in-depth constraints operating independently</li></ul><p><strong>Challenge 3: Capability Extension</strong></p><ul><li>Terminal agents need diverse tools (compilers, package managers, debugging tools, etc.)</li><li>Enumerating all tools exhausts the token budget</li><li>Need: Lazy tool discovery and just-in-time capability exposure</li></ul><h3 id="_1-2-opendev-approach" tabindex="-1">1.2 OpenDev Approach <a class="header-anchor" href="#_1-2-opendev-approach" aria-label="Permalink to &quot;1.2 OpenDev Approach&quot;">​</a></h3><p>OpenDev is an open-source terminal-native agent addressing these challenges through:</p><ol><li><strong>Compound AI architecture</strong>: Specialized models for different cognitive roles</li><li><strong>Dual-agent separation</strong>: Planner (strategic) and Executor (tactical)</li><li><strong>Multi-layer safety</strong>: Independent constraint layers (prompt, schema, runtime, tool, lifecycle)</li><li><strong>Intelligent context engineering</strong>: Dynamic system prompt, tool result optimization, adaptive compaction</li><li><strong>Memory mechanisms</strong>: Session-persistent knowledge accumulation</li><li><strong>Lazy tool discovery</strong>: Just-in-time capability exposure via MCP</li></ol><h3 id="_1-3-design-principles" tabindex="-1">1.3 Design Principles <a class="header-anchor" href="#_1-3-design-principles" aria-label="Permalink to &quot;1.3 Design Principles&quot;">​</a></h3><ol><li><strong>Separation of concerns</strong>: Each architectural decision remains independently configurable</li><li><strong>Progressive degradation</strong>: System functions gracefully as resources (tokens, time, compute) exhaust</li><li><strong>Transparency over abstraction</strong>: All actions remain observable and overridable by human operators</li></ol><h2 id="_2-architecture-overview" tabindex="-1">2. Architecture Overview <a class="header-anchor" href="#_2-architecture-overview" aria-label="Permalink to &quot;2. Architecture Overview&quot;">​</a></h2><h3 id="_2-1-four-layer-architecture" tabindex="-1">2.1 Four-Layer Architecture <a class="header-anchor" href="#_2-1-four-layer-architecture" aria-label="Permalink to &quot;2.1 Four-Layer Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│   Entry &amp; UI Layer                  │</span></span>
<span class="line"><span>│   (CLI, TUI, Web interfaces)        │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Agent Core Layer                  │</span></span>
<span class="line"><span>│   (Reasoning &amp; Orchestration)       │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Tool &amp; Context Layers             │</span></span>
<span class="line"><span>│   (Execution &amp; Context Management)  │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Persistence Layer                 │</span></span>
<span class="line"><span>│   (Sessions, Config, Logs)          │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><h4 id="entry-ui-layer" tabindex="-1">Entry &amp; UI Layer <a class="header-anchor" href="#entry-ui-layer" aria-label="Permalink to &quot;Entry &amp; UI Layer&quot;">​</a></h4><ul><li>Command-line interface (primary)</li><li>Text-based user interface (TUI) for interactive sessions</li><li>Web interface for remote monitoring</li><li>Natural language input for task specification</li></ul><h4 id="agent-core-layer" tabindex="-1">Agent Core Layer <a class="header-anchor" href="#agent-core-layer" aria-label="Permalink to &quot;Agent Core Layer&quot;">​</a></h4><ul><li><strong>Planner agent</strong>: Strategic reasoning about task decomposition</li><li><strong>Executor agent</strong>: Tactical execution of specific commands</li><li><strong>Critic agent</strong>: Self-evaluation and improvement suggestions</li><li><strong>Orchestrator</strong>: Routing between agents, context management</li></ul><h4 id="tool-context-layers" tabindex="-1">Tool &amp; Context Layers <a class="header-anchor" href="#tool-context-layers" aria-label="Permalink to &quot;Tool &amp; Context Layers&quot;">​</a></h4><ul><li><strong>Tool interface</strong>: MCP-based tool discovery and invocation</li><li><strong>Context assembly</strong>: Dynamic system prompt construction</li><li><strong>Memory interface</strong>: Session history and persistent notes</li><li><strong>Sandbox interface</strong>: Shell execution environment</li></ul><h4 id="persistence-layer" tabindex="-1">Persistence Layer <a class="header-anchor" href="#persistence-layer" aria-label="Permalink to &quot;Persistence Layer&quot;">​</a></h4><ul><li><strong>Session store</strong>: Task state and execution history</li><li><strong>Configuration store</strong>: User preferences and policies</li><li><strong>Operation logs</strong>: Complete audit trail of all actions</li></ul><h3 id="_2-2-five-safety-layers-defense-in-depth" tabindex="-1">2.2 Five Safety Layers (Defense in Depth) <a class="header-anchor" href="#_2-2-five-safety-layers-defense-in-depth" aria-label="Permalink to &quot;2.2 Five Safety Layers (Defense in Depth)&quot;">​</a></h3><p>The system enforces security through independent layers, each capable of preventing harmful operations:</p><h4 id="layer-1-prompt-level-guardrails" tabindex="-1">Layer 1: Prompt-Level Guardrails <a class="header-anchor" href="#layer-1-prompt-level-guardrails" aria-label="Permalink to &quot;Layer 1: Prompt-Level Guardrails&quot;">​</a></h4><ul><li>Explicit instructions in system prompt preventing destructive operations</li><li>Role-based behavioral guidelines (planner vs. executor)</li><li>Ethical guidelines and transparency requirements</li><li>Example: &quot;You may not delete files without explicit user confirmation&quot;</li></ul><h4 id="layer-2-schema-level-restrictions" tabindex="-1">Layer 2: Schema-Level Restrictions <a class="header-anchor" href="#layer-2-schema-level-restrictions" aria-label="Permalink to &quot;Layer 2: Schema-Level Restrictions&quot;">​</a></h4><ul><li>Action space definitions restrict available operations</li><li>Tool schemas include safety constraints (e.g., file deletion requires flag confirmation)</li><li>Only safe tool variants exposed to agent</li><li>Example: rm command only available with --confirm flag</li></ul><h4 id="layer-3-runtime-approval-systems" tabindex="-1">Layer 3: Runtime Approval Systems <a class="header-anchor" href="#layer-3-runtime-approval-systems" aria-label="Permalink to &quot;Layer 3: Runtime Approval Systems&quot;">​</a></h4><ul><li>Destructive operations (delete, modify critical files) require explicit approval</li><li>Human review before execution of risky operations</li><li>Approval tracked for audit purposes</li><li>Example: &quot;Execute deletion of ~/.bashrc? [y/n]&quot;</li></ul><h4 id="layer-4-tool-level-validation" tabindex="-1">Layer 4: Tool-Level Validation <a class="header-anchor" href="#layer-4-tool-level-validation" aria-label="Permalink to &quot;Layer 4: Tool-Level Validation&quot;">​</a></h4><ul><li>Pre-execution validation of tool invocations</li><li>Post-execution result verification</li><li>Sandboxing and resource limits</li><li>Example: File path validation prevents directory traversal attacks</li></ul><h4 id="layer-5-user-defined-lifecycle-hooks" tabindex="-1">Layer 5: User-Defined Lifecycle Hooks <a class="header-anchor" href="#layer-5-user-defined-lifecycle-hooks" aria-label="Permalink to &quot;Layer 5: User-Defined Lifecycle Hooks&quot;">​</a></h4><ul><li>Custom validation functions at key execution points</li><li>Task-specific safety policies</li><li>Integration with external security systems</li><li>Example: Custom hook checks file deletions against protected-files list</li></ul><p><strong>Key principle</strong>: No single failure compromises security. Multiple independent layers must be bypassed to enable harmful operations.</p><h3 id="_2-3-extended-react-loop" tabindex="-1">2.3 Extended ReAct Loop <a class="header-anchor" href="#_2-3-extended-react-loop" aria-label="Permalink to &quot;2.3 Extended ReAct Loop&quot;">​</a></h3><p>OpenDev implements a six-phase execution loop per step:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase 1: Context Compaction</span></span>
<span class="line"><span>├─ Assess context window utilization</span></span>
<span class="line"><span>├─ Compact history if necessary</span></span>
<span class="line"><span>└─ Maintain working set of essential information</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 2: Optional Thinking</span></span>
<span class="line"><span>├─ Enable extended reasoning (optional)</span></span>
<span class="line"><span>├─ Chain-of-thought before action generation</span></span>
<span class="line"><span>└─ Useful for complex decisions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 3: Self-Critique</span></span>
<span class="line"><span>├─ Evaluate previous action outcomes</span></span>
<span class="line"><span>├─ Identify errors or suboptimal choices</span></span>
<span class="line"><span>└─ Suggest corrective actions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 4: Action Generation</span></span>
<span class="line"><span>├─ Generate next action(s)</span></span>
<span class="line"><span>├─ Provide rationale</span></span>
<span class="line"><span>└─ Tag actions by category (file, execute, investigate)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 5: Tool Execution</span></span>
<span class="line"><span>├─ Execute approved actions</span></span>
<span class="line"><span>├─ Capture output and side effects</span></span>
<span class="line"><span>└─ Log all operations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 6: Post-Processing</span></span>
<span class="line"><span>├─ Extract relevant information from output</span></span>
<span class="line"><span>├─ Update session state</span></span>
<span class="line"><span>├─ Prepare context for next iteration</span></span></code></pre></div><h2 id="_3-context-engineering" tabindex="-1">3. Context Engineering <a class="header-anchor" href="#_3-context-engineering" aria-label="Permalink to &quot;3. Context Engineering&quot;">​</a></h2><h3 id="_3-1-finite-context-as-primary-constraint" tabindex="-1">3.1 Finite Context as Primary Constraint <a class="header-anchor" href="#_3-1-finite-context-as-primary-constraint" aria-label="Permalink to &quot;3.1 Finite Context as Primary Constraint&quot;">​</a></h3><p>OpenDev treats context window management as a primary design concern, not an afterthought.</p><p><strong>Key metrics</strong>:</p><ul><li>Input context size: Typically 150–200K tokens for extended sessions</li><li>Output budget per step: 500–1500 tokens (variable by model)</li><li>Total per-session budget: 1M–5M tokens depending on configuration</li><li>Session duration: Hours of wall-clock time, hundreds of steps</li></ul><h3 id="_3-2-dynamic-system-prompt" tabindex="-1">3.2 Dynamic System Prompt <a class="header-anchor" href="#_3-2-dynamic-system-prompt" aria-label="Permalink to &quot;3.2 Dynamic System Prompt&quot;">​</a></h3><p>Rather than static system prompt, OpenDev constructs prompts dynamically:</p><p><strong>Core components</strong>:</p><ul><li>Base role definition (planner, executor, etc.)</li><li>Current goal and progress status</li><li>Recent action history (compressed)</li><li>Tool availability (lazy loaded)</li><li>Context budget reminder</li><li>Safety policies (most critical only)</li></ul><p><strong>Example dynamic construction</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You are the Executor agent for software development tasks.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Current Task: Fix memory leak in auth module</span></span>
<span class="line"><span>Progress: 3 of 8 subtasks complete</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent History:</span></span>
<span class="line"><span>- Added debug logging to auth.cpp (done)</span></span>
<span class="line"><span>- Ran valgrind on auth module (in progress)</span></span>
<span class="line"><span>- Next: Analyze valgrind output and locate leak source</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Available Tools: [shell, file_read, file_write, grep, valgrind]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Context Budget: 60% remaining (60K / 100K tokens)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Safety: Do not modify or delete test files. Approve destructive </span></span>
<span class="line"><span>operations with user.</span></span></code></pre></div><h3 id="_3-3-tool-result-optimization" tabindex="-1">3.3 Tool Result Optimization <a class="header-anchor" href="#_3-3-tool-result-optimization" aria-label="Permalink to &quot;3.3 Tool Result Optimization&quot;">​</a></h3><p>Terminal output is often verbose and redundant. OpenDev intelligently compacts tool results:</p><p><strong>Optimization strategies</strong>:</p><ol><li><p><strong>Truncation with context preservation</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Command: ls -la /project (output: 500 lines)</span></span>
<span class="line"><span>Preserved: First 10 lines (directory structure)</span></span>
<span class="line"><span>            Last 10 lines (summary)</span></span>
<span class="line"><span>Removed: Middle 480 lines (repetitive entries)</span></span></code></pre></div></li><li><p><strong>Syntax highlighting removal</strong>:</p><ul><li>Strip ANSI color codes</li><li>Preserve structural information</li><li>Reduce token count by 10–20%</li></ul></li><li><p><strong>Error message summarization</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Full compiler output: 2000 lines</span></span>
<span class="line"><span>Summarized: </span></span>
<span class="line"><span>- Error count: 5</span></span>
<span class="line"><span>- Error types: [undefined_reference, type_mismatch]</span></span>
<span class="line"><span>- First error: undefined reference to &#39;malloc&#39; in line 42</span></span>
<span class="line"><span>- Suggestion: Check includes and linking</span></span></code></pre></div></li><li><p><strong>Duplicate suppression</strong>:</p><ul><li>Many tools repeat output (e.g., build systems)</li><li>Cache results, only provide deltas</li></ul></li></ol><h3 id="_3-4-dual-memory-architecture" tabindex="-1">3.4 Dual-Memory Architecture <a class="header-anchor" href="#_3-4-dual-memory-architecture" aria-label="Permalink to &quot;3.4 Dual-Memory Architecture&quot;">​</a></h3><p>The system maintains two memory structures:</p><p><strong>Working Memory</strong> (in-prompt context):</p><ul><li>Current goal and subgoals</li><li>Last 5–10 actions and results</li><li>Critical information (file paths, error messages)</li><li>Size: 10–20K tokens</li><li>Lifespan: Current session</li></ul><p><strong>Episodic Memory</strong> (persistent storage):</p><ul><li>Project structure and layout</li><li>Key files and their purposes</li><li>Previous solutions to similar problems</li><li>Discovered patterns and lessons</li><li>Size: Grows across sessions</li><li>Lifespan: Indefinite (project lifetime)</li></ul><p><strong>Interaction</strong>:</p><ul><li>Working memory handles immediate decisions</li><li>Episodic memory provides context continuity</li><li>Periodic consolidation moves insights from working → episodic</li><li>Retrieval-augmented generation incorporates relevant episodic memories</li></ul><h3 id="_3-5-context-aware-reminders" tabindex="-1">3.5 Context-Aware Reminders <a class="header-anchor" href="#_3-5-context-aware-reminders" aria-label="Permalink to &quot;3.5 Context-Aware Reminders&quot;">​</a></h3><p>To counteract instruction degradation over time:</p><p><strong>Event-driven reminders</strong>:</p><ul><li>Safety reminders triggered by risky operations</li><li>Goal reminders triggered by tangential actions</li><li>Resource reminders when context approaches limits</li><li>Progress reminders at regular intervals</li></ul><p><strong>Example reminder sequence</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: [normal operation, agent understands goal]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>Step 20: [agent begins tangential investigation, drifting from goal]</span></span>
<span class="line"><span>→ Reminder: &quot;Your goal is to fix memory leak in auth module, not to </span></span>
<span class="line"><span>            refactor database code. Return to goal?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 40: [agent continuing on wrong track]</span></span>
<span class="line"><span>→ Critical reminder: &quot;You have spent 40 steps on database refactoring.</span></span>
<span class="line"><span>                    Return to original goal immediately.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 50: [context at 85% usage]</span></span>
<span class="line"><span>→ Resource reminder: &quot;Context at 85%. Begin preparing for conclusion</span></span>
<span class="line"><span>                    or context compaction.&quot;</span></span></code></pre></div><h3 id="_3-6-adaptive-compaction" tabindex="-1">3.6 Adaptive Compaction <a class="header-anchor" href="#_3-6-adaptive-compaction" aria-label="Permalink to &quot;3.6 Adaptive Compaction&quot;">​</a></h3><p>When context reaches threshold (typically 80% utilization):</p><ol><li><p><strong>Identify essential information</strong>:</p><ul><li>Core goal and constraints</li><li>Recent action history (last 10 steps)</li><li>Current state and findings</li><li>Critical errors or blockers</li></ul></li><li><p><strong>Compress history</strong>:</p><ul><li>Summarize early actions into high-level observations</li><li>Merge similar consecutive operations</li><li>Remove redundant information</li><li>Size reduction: Typically 40–60%</li></ul></li><li><p><strong>Preserve continuity</strong>:</p><ul><li>Maintain causality (actions → outcomes)</li><li>Keep enough detail for error diagnosis</li><li>Support rollback to previous decision points</li></ul></li><li><p><strong>Restart loop</strong> with compacted context</p></li></ol><h2 id="_4-multi-model-architecture" tabindex="-1">4. Multi-Model Architecture <a class="header-anchor" href="#_4-multi-model-architecture" aria-label="Permalink to &quot;4. Multi-Model Architecture&quot;">​</a></h2><p>OpenDev assigns different cognitive tasks to specialized models:</p><table tabindex="0"><thead><tr><th>Role</th><th>Typical Model</th><th>Purpose</th><th>Token Budget</th></tr></thead><tbody><tr><td>Normal execution</td><td>Claude 3.5 Sonnet</td><td>Default reasoning and planning</td><td>2000</td></tr><tr><td>Thinking</td><td>Claude 3.5 Opus</td><td>Extended reasoning for complex decisions</td><td>5000</td></tr><tr><td>Critique</td><td>Claude 3.5 Sonnet</td><td>Self-evaluation and error analysis</td><td>1000</td></tr><tr><td>Vision</td><td>Claude 3.5 Sonnet</td><td>Visual analysis (screenshots, code review)</td><td>3000</td></tr><tr><td>Expert</td><td>Claude 3.5 Opus</td><td>Domain-specific reasoning (compilers, DB, etc.)</td><td>5000</td></tr></tbody></table><p><strong>Benefits</strong>:</p><ul><li>Cost optimization: Use cheaper models for routine tasks</li><li>Latency optimization: Parallelizable thinking and critique</li><li>Quality optimization: Expert models for hard decisions</li></ul><h2 id="_5-dual-agent-separation-planner-vs-executor" tabindex="-1">5. Dual-Agent Separation: Planner vs. Executor <a class="header-anchor" href="#_5-dual-agent-separation-planner-vs-executor" aria-label="Permalink to &quot;5. Dual-Agent Separation: Planner vs. Executor&quot;">​</a></h2><h3 id="_5-1-planner-agent" tabindex="-1">5.1 Planner Agent <a class="header-anchor" href="#_5-1-planner-agent" aria-label="Permalink to &quot;5.1 Planner Agent&quot;">​</a></h3><p><strong>Responsibility</strong>: Strategic task decomposition and planning</p><p><strong>Capabilities</strong>:</p><ul><li>Break down complex goals into subgoals</li><li>Decide on tool combinations and sequences</li><li>Identify dependencies and critical paths</li><li>Estimate effort and complexity</li></ul><p><strong>Token allocation</strong>: 2000–3000 tokens <strong>Execution frequency</strong>: Once per major task phase <strong>Interaction</strong>: Guides executor but does not directly execute</p><p><strong>Example plan</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Goal: Fix authentication service memory leak</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Plan:</span></span>
<span class="line"><span>1. Investigate: Understand service architecture and memory usage</span></span>
<span class="line"><span>   - Read design documents</span></span>
<span class="line"><span>   - Run top/htop to see memory consumption</span></span>
<span class="line"><span>   - Identify memory-hungry components</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Trace: Isolate leak source</span></span>
<span class="line"><span>   - Enable debug logging</span></span>
<span class="line"><span>   - Run under memory profiler (valgrind)</span></span>
<span class="line"><span>   - Capture stack traces of allocations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Fix: Implement and test fix</span></span>
<span class="line"><span>   - Modify identified code</span></span>
<span class="line"><span>   - Recompile</span></span>
<span class="line"><span>   - Re-run profiler to verify leak elimination</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Validate: Ensure fix doesn&#39;t regress</span></span>
<span class="line"><span>   - Run full test suite</span></span>
<span class="line"><span>   - Monitor in staging environment</span></span>
<span class="line"><span>   - Deploy to production with monitoring</span></span></code></pre></div><h3 id="_5-2-executor-agent" tabindex="-1">5.2 Executor Agent <a class="header-anchor" href="#_5-2-executor-agent" aria-label="Permalink to &quot;5.2 Executor Agent&quot;">​</a></h3><p><strong>Responsibility</strong>: Tactical execution of specific actions</p><p><strong>Capabilities</strong>:</p><ul><li>Execute individual shell commands</li><li>Read and modify files</li><li>Interact with tools (compiler, debugger, version control)</li><li>Handle errors and retries</li></ul><p><strong>Token allocation</strong>: 1500–2500 tokens per step <strong>Execution frequency</strong>: Multiple times per minute <strong>Interaction</strong>: Reports status to planner</p><p><strong>Example execution</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Planner Goal: &quot;Understand service architecture&quot;</span></span>
<span class="line"><span>Executor Actions:</span></span>
<span class="line"><span>1. Find and read README.md</span></span>
<span class="line"><span>2. Find and read architecture.md</span></span>
<span class="line"><span>3. Run &#39;du -sh&#39; to understand directory structure</span></span>
<span class="line"><span>4. Run &#39;top -p $(pgrep auth-service)&#39; to see memory usage</span></span>
<span class="line"><span>5. Report findings to planner</span></span></code></pre></div><h2 id="_6-lazy-tool-discovery-mcp" tabindex="-1">6. Lazy Tool Discovery (MCP) <a class="header-anchor" href="#_6-lazy-tool-discovery-mcp" aria-label="Permalink to &quot;6. Lazy Tool Discovery (MCP)&quot;">​</a></h2><p>Rather than enumerating all tools upfront:</p><p><strong>Standard approach</strong> (problematic):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Available tools: [shell, python, node, rust, gcc, clang, go, </span></span>
<span class="line"><span>                  docker, k8s, terraform, ansible, npm, pip, </span></span>
<span class="line"><span>                  git, svn, postgresql, mysql, redis, ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Token cost: 5000+ tokens just to list tools!</span></span></code></pre></div><p><strong>OpenDev approach</strong> (lazy loading):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Base tools: [shell, file_read, file_write]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>When agent needs additional tools:</span></span>
<span class="line"><span>1. Request tool discovery: &quot;I need to compile this C++ file&quot;</span></span>
<span class="line"><span>2. OpenDev loads compiler tools dynamically: [gcc, clang, make, cmake]</span></span>
<span class="line"><span>3. Compiler tools added to context</span></span>
<span class="line"><span>4. Agent uses tools</span></span>
<span class="line"><span>5. Tools unloaded when session ends</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Token cost: ~500 tokens for lazy-loaded tools, only when needed</span></span></code></pre></div><p><strong>Benefits</strong>:</p><ul><li>Keeps context lean (only load tools actually needed)</li><li>Supports arbitrary tool ecosystem (any MCP-compatible tool)</li><li>Enables new tools mid-session without context reload</li><li>Reduces cognitive load on agent</li></ul><h2 id="_7-session-management-and-memory" tabindex="-1">7. Session Management and Memory <a class="header-anchor" href="#_7-session-management-and-memory" aria-label="Permalink to &quot;7. Session Management and Memory&quot;">​</a></h2><h3 id="_7-1-session-state-persistence" tabindex="-1">7.1 Session State Persistence <a class="header-anchor" href="#_7-1-session-state-persistence" aria-label="Permalink to &quot;7.1 Session State Persistence&quot;">​</a></h3><p>Each session maintains:</p><ul><li><strong>Task description and goals</strong></li><li><strong>Execution history</strong>: All commands and outputs (full fidelity)</li><li><strong>Session metadata</strong>: Start time, model, budget, safety policies</li><li><strong>Checkpoints</strong>: Snapshots at decision points for rollback</li></ul><p><strong>Persistence benefits</strong>:</p><ul><li>Resume after interruption (human or system timeout)</li><li>Audit trail for all operations</li><li>Rollback to previous decision point if needed</li><li>Learning from past sessions</li></ul><h3 id="_7-2-knowledge-accumulation" tabindex="-1">7.2 Knowledge Accumulation <a class="header-anchor" href="#_7-2-knowledge-accumulation" aria-label="Permalink to &quot;7.2 Knowledge Accumulation&quot;">​</a></h3><p>Across sessions on the same project:</p><p><strong>Learned patterns</strong>:</p><ul><li>&quot;Repository uses Bazel for builds&quot; (structural knowledge)</li><li>&quot;Test suite takes 15 minutes to run&quot; (performance knowledge)</li><li>&quot;Breaking change in v2.5 of library X&quot; (domain knowledge)</li></ul><p><strong>Implementation</strong>:</p><ul><li>After each session, extract key insights</li><li>Consolidate into project-specific knowledge base</li><li>Pre-load knowledge base at session start</li><li>Continuous improvement over repeated interactions</li></ul><h3 id="_7-3-session-types" tabindex="-1">7.3 Session Types <a class="header-anchor" href="#_7-3-session-types" aria-label="Permalink to &quot;7.3 Session Types&quot;">​</a></h3><p><strong>Interactive sessions</strong>:</p><ul><li>Human actively monitoring and guiding agent</li><li>Approval required for risky operations</li><li>Real-time feedback integration</li><li>Suitable for critical tasks</li></ul><p><strong>Batch sessions</strong>:</p><ul><li>Agent runs unsupervised</li><li>Predefined constraints and budgets</li><li>Checkpoints at safe points</li><li>Suitable for routine maintenance</li></ul><p><strong>Hybrid sessions</strong>:</p><ul><li>Agent can request human input</li><li>Timeout and escalation mechanisms</li><li>Graceful degradation if human unavailable</li><li>Suitable for complex tasks with uncertainty</li></ul><h2 id="_8-experimental-evaluation" tabindex="-1">8. Experimental Evaluation <a class="header-anchor" href="#_8-experimental-evaluation" aria-label="Permalink to &quot;8. Experimental Evaluation&quot;">​</a></h2><h3 id="_8-1-benchmarks" tabindex="-1">8.1 Benchmarks <a class="header-anchor" href="#_8-1-benchmarks" aria-label="Permalink to &quot;8.1 Benchmarks&quot;">​</a></h3><p><strong>Primary benchmarks</strong>:</p><ul><li>SWE-bench Verified (500 software engineering tasks)</li><li>Repository editing and debugging tasks</li><li>Multi-file refactoring challenges</li></ul><p><strong>Secondary benchmarks</strong>:</p><ul><li>Context efficiency: Token usage per task</li><li>Safety: Dangerous operations attempted / blocked</li><li>Memory accumulation: Knowledge growth across sessions</li></ul><h3 id="_8-2-key-metrics" tabindex="-1">8.2 Key Metrics <a class="header-anchor" href="#_8-2-key-metrics" aria-label="Permalink to &quot;8.2 Key Metrics&quot;">​</a></h3><p><strong>Effectiveness</strong>:</p><ul><li>Task success rate (resolved vs. attempted)</li><li>Partial success rate</li><li>Time to success</li></ul><p><strong>Efficiency</strong>:</p><ul><li>Tokens per success</li><li>Actions per success</li><li>Wall-clock time per task</li></ul><p><strong>Safety</strong>:</p><ul><li>Dangerous operations initiated</li><li>False positives (blocked safe operations)</li><li>Audit trail completeness</li></ul><h3 id="_8-3-baseline-comparisons" tabindex="-1">8.3 Baseline Comparisons <a class="header-anchor" href="#_8-3-baseline-comparisons" aria-label="Permalink to &quot;8.3 Baseline Comparisons&quot;">​</a></h3><p>Compared against:</p><ul><li>SWE-agent: 41% on SWE-bench Verified</li><li>OpenDev (this work): 48% on SWE-bench Verified</li><li>Specialized coding agents: Context-dependent performance</li></ul><p><strong>Key insight</strong>: Robust context engineering and multi-layer safety enable competitive performance while maintaining auditability.</p><h2 id="_9-design-patterns-observed" tabindex="-1">9. Design Patterns Observed <a class="header-anchor" href="#_9-design-patterns-observed" aria-label="Permalink to &quot;9. Design Patterns Observed&quot;">​</a></h2><h3 id="_9-1-successful-patterns" tabindex="-1">9.1 Successful Patterns <a class="header-anchor" href="#_9-1-successful-patterns" aria-label="Permalink to &quot;9.1 Successful Patterns&quot;">​</a></h3><p><strong>Pattern 1: Problem decomposition</strong></p><ul><li>Planner breaks task into subtasks</li><li>Executor focuses on single subtask</li><li>Results accumulate to solve original problem</li></ul><p><strong>Pattern 2: Exploration before action</strong></p><ul><li>Read before write</li><li>Question before commit</li><li>Investigate before execute</li></ul><p><strong>Pattern 3: Resumable steps</strong></p><ul><li>Each action produces checkpoint</li><li>Can resume from any checkpoint</li><li>Enables long-running tasks</li></ul><h3 id="_9-2-common-failure-modes" tabindex="-1">9.2 Common Failure Modes <a class="header-anchor" href="#_9-2-common-failure-modes" aria-label="Permalink to &quot;9.2 Common Failure Modes&quot;">​</a></h3><p><strong>Mode 1: Context drift</strong></p><ul><li>Agent forgets original goal mid-task</li><li>Mitigated by: Goal reminders, periodic replanning</li></ul><p><strong>Mode 2: Shallow exploration</strong></p><ul><li>Agent tries single approach, fails</li><li>Mitigated by: Encourage diverse strategies, retry limits</li></ul><p><strong>Mode 3: Safety violation</strong></p><ul><li>Agent attempts unsafe operation</li><li>Mitigated by: Multiple independent safety layers, explicit approval</li></ul><h2 id="_10-lessons-learned" tabindex="-1">10. Lessons Learned <a class="header-anchor" href="#_10-lessons-learned" aria-label="Permalink to &quot;10. Lessons Learned&quot;">​</a></h2><h3 id="_10-1-context-engineering-is-foundational" tabindex="-1">10.1 Context Engineering is Foundational <a class="header-anchor" href="#_10-1-context-engineering-is-foundational" aria-label="Permalink to &quot;10.1 Context Engineering is Foundational&quot;">​</a></h3><p><strong>Lesson</strong>: Context management is not an optimization; it is a first-order design decision.</p><ul><li>Decisions made early (tool result compaction, memory architecture) cascade throughout system</li><li>Late-stage optimization often ineffective</li><li>Treat context budget as primary resource constraint (like compute or latency)</li></ul><h3 id="_10-2-separation-of-concerns-enables-robustness" tabindex="-1">10.2 Separation of Concerns Enables Robustness <a class="header-anchor" href="#_10-2-separation-of-concerns-enables-robustness" aria-label="Permalink to &quot;10.2 Separation of Concerns Enables Robustness&quot;">​</a></h3><p><strong>Lesson</strong>: Independent safety layers, separate agents, modular architecture increase reliability.</p><ul><li>No single failure mode compromises system</li><li>Failures are isolatable and debuggable</li><li>Changes to one component do not affect others</li></ul><h3 id="_10-3-transparency-over-abstraction" tabindex="-1">10.3 Transparency Over Abstraction <a class="header-anchor" href="#_10-3-transparency-over-abstraction" aria-label="Permalink to &quot;10.3 Transparency Over Abstraction&quot;">​</a></h3><p><strong>Lesson</strong>: Explicit, observable behavior often better than &quot;smart&quot; hidden behavior.</p><ul><li>Agents should explain their reasoning</li><li>Actions should be auditable</li><li>Trade-offs between efficiency and observability should be explicit</li></ul><h3 id="_10-4-memory-as-capability" tabindex="-1">10.4 Memory as Capability <a class="header-anchor" href="#_10-4-memory-as-capability" aria-label="Permalink to &quot;10.4 Memory as Capability&quot;">​</a></h3><p><strong>Lesson</strong>: Session persistence and knowledge accumulation are not features; they are essential for autonomous long-horizon tasks.</p><ul><li>First session: Agent stumbles, learns basics</li><li>Subsequent sessions: Agent applies learned patterns</li><li>Accumulation over time improves reliability</li></ul><h2 id="_11-future-work" tabindex="-1">11. Future Work <a class="header-anchor" href="#_11-future-work" aria-label="Permalink to &quot;11. Future Work&quot;">​</a></h2><ul><li><strong>Cross-project learning</strong>: Knowledge transfer across different projects</li><li><strong>Collaborative agents</strong>: Multiple agents working on same task in parallel</li><li><strong>Continuous improvement</strong>: Automated harness optimization (per Meta-Harness)</li><li><strong>Diverse domains</strong>: Extend beyond software engineering to DevOps, system administration</li><li><strong>Human-in-the-loop optimization</strong>: Active learning from user feedback</li></ul><h2 id="_12-conclusion" tabindex="-1">12. Conclusion <a class="header-anchor" href="#_12-conclusion" aria-label="Permalink to &quot;12. Conclusion&quot;">​</a></h2><p>OpenDev demonstrates that terminal-native coding agents can be built with:</p><ul><li>Robust context engineering (dynamic prompts, tool optimization, adaptive compaction)</li><li>Multi-layer safety (independent constraints at prompt, schema, runtime, tool, and lifecycle levels)</li><li>Intelligent architecture (specialized models, dual-agent separation, lazy tool discovery)</li><li>Session management (persistence, memory accumulation, resumable checkpoints)</li></ul><p><strong>Key contribution</strong>: First comprehensive technical report for an open-source, terminal-native, interactive coding agent, bridging academic research and production implementation practices.</p><p><strong>Code availability</strong>: <a href="https://github.com/zeuikli/opendev" target="_blank" rel="noreferrer">https://github.com/zeuikli/opendev</a> (open-source under CC BY 4.0)</p><hr><p><strong>Citation</strong>: Bui, N. D. Q. (2026). Building AI coding agents for the terminal: Scaffolding, harness, context engineering, and lessons learned. <em>arXiv preprint arXiv:2603.05344</em>.</p>`,179)])])}const m=n(t,[["render",o]]);export{g as __pageData,m as default};
